sql:
SELECT AVG(average_class_size) AS avg_class_size
FROM education_statistics
WHERE year_id = 1;

SELECT AVG(dropout_rate) AS average_dropout_rate
FROM dropout_rates
WHERE state_id = 1 AND year_id = 1;

SELECT literacy_rate
FROM literacy_rates
WHERE state_id = 1 AND school_type_id = 0;

SELECT SUM(enrollment) AS total_enrollment
FROM school_enrollment
WHERE state_id = 1 AND school_type_id = 1 AND year_id = 1;

SELECT state_name 
FROM states 
ORDER BY state_name;

SELECT expenditure_amount
FROM expenditure
WHERE state_id = 0 AND school_type_id = 1 AND year_id = 1;
